mapper.select:
SELECT ea.id, ea.title, ea.category, ea.content, ea.expert_name as author, ea.view_count as viewCount, ea.thumb_count as thumbCount, ea.create_time as createTime FROM expert_advice ea WHERE ea.deleted = 0 AND ea.status = 1
AND ea.expert_id = #{expertId}
AND ea.category = #{category}
ORDER BY ea.create_time DESC
